async def main(args: Args) -> Output:
    import re

    params = args.params
    content = str(params.get('content') or '').strip()
    if not content:
        return {"texts": ""}

    text = re.sub(r'[“”‘’"\'\[\]()（）/\\《》]+', '', content)
    text = re.sub(r'[\r\n]+', '', text)
    text = re.sub(r'\s+', '', text)

    connectors = [
        '但是', '可是', '不过', '因为', '所以', '于是', '然后', '后来', '同时',
        '而且', '并且', '如果', '虽然', '其实', '比如', '尤其', '再说', '再看',
        '很多人只知道', '你以为', '真正', '更狠的是', '可这还没完',
        '直到', '自此', '从那以后', '也正因如此'
    ]

    def find_cut_position(piece, target=18):
        piece = str(piece or '')
        if len(piece) <= target + 3:
            return len(piece)

        candidate_positions = []
        for m in re.finditer(r'[，、：:；;]', piece):
            pos = m.start()
            if 6 <= pos <= target + 4:
                candidate_positions.append((abs(pos - target), pos))
        for word in connectors:
            idx = piece.find(word, 5)
            while idx != -1:
                if 6 <= idx <= target + 4:
                    candidate_positions.append((abs(idx - target) + 0.5, idx))
                idx = piece.find(word, idx + len(word))

        if candidate_positions:
            candidate_positions.sort(key=lambda x: (x[0], -x[1]))
            return candidate_positions[0][1]

        fallback = min(max(target, 8), len(piece))
        return fallback

    def split_piece(piece, target=18):
        piece = str(piece or '').strip('，、：:；; ')
        if not piece:
            return []

        clauses = [p.strip('，、：:；; ') for p in re.split(r'[，、：:；;]', piece) if p and p.strip('，、：:；; ')]
        if not clauses:
            clauses = [piece]

        merged = []
        current = ''
        for clause in clauses:
            if not current:
                current = clause
                continue
            if len(current) + len(clause) <= target:
                current = f"{current}，{clause}"
            else:
                merged.append(current)
                current = clause
        if current:
            merged.append(current)

        final_chunks = []
        for chunk in merged:
            chunk = chunk.strip('，、：:；; ')
            while len(chunk) > target + 3:
                cut = find_cut_position(chunk, target)
                head = chunk[:cut].strip('，、：:；; ')
                tail = chunk[cut:].strip('，、：:；; ')
                if head:
                    final_chunks.append(head)
                chunk = tail
            if chunk:
                final_chunks.append(chunk)

        refined = []
        for chunk in final_chunks:
            if refined and len(chunk) <= 4:
                refined[-1] = f"{refined[-1]}，{chunk}"
            else:
                refined.append(chunk)
        return refined

    sentence_pieces = [p for p in re.split(r'[。！？；.!?;]+', text) if p and p.strip()]
    items = []
    for piece in sentence_pieces:
        items.extend(split_piece(piece, target=18))

    if not items:
        items = split_piece(text, target=18) or [content]

    return {"texts": "\n".join(items)}

import re

def normalize_myth_terms(text):
    value = str(text or '')
    replacements = {
        '历节': '历劫',
        '节数': '劫数',
        '节难': '劫难',
    }
    for wrong, correct in replacements.items():
        value = value.replace(wrong, correct)
    return value

def clean_caption_text(text):
    value = normalize_myth_terms(text).strip()
    if not value:
        return ''
    value = re.sub(r'[“”‘’"\'《》\[\]()（）/\\]+', '', value)
    value = re.sub(r'[，,。！？!?；;、：:…]+', ' ', value)
    value = re.sub(r'\s+', ' ', value).strip()
    return value

