    timelines = _as_list(params.get('timelines'))
    source_texts = _normalize_text_list(params.get('source_texts'))
    texts = _normalize_text_list(params.get('texts'))
    aligned_texts = texts or source_texts
    audio = params.get('audio')
    duration = float(params.get('duration') or 0)
    image_url = params.get('image_url')
    pre_time = int(params.get('pre_time') or 0)
    segment_duration = max(int(duration * 1000000), 0)
    if audio and segment_duration > 0:
        audios.append({
            "audio_url": audio,
            "duration": segment_duration,
            "start": pre_time,
            "end": pre_time + segment_duration,
        })
    primary = str(image_url or '').strip()
    scene_image = primary if primary else '__MISSING_SCENE_IMAGE__'
    videos.append('')
    images.append(scene_image)
    for index2, obj in enumerate(timelines):
        if not isinstance(obj, dict):
            continue
        start = obj.get('start')
        end = obj.get('end')
        if index2 < len(aligned_texts):
            text = aligned_texts[index2]
        elif index2 < len(source_texts):
            text = source_texts[index2]
        else:
            text = ''
        if start is None or end is None or not text:
            continue
        start_at = int(pre_time + start)
        end_at = int(pre_time + end)
