            continue
        captions.append({
            'text': text,
            'start': start_at,
            'end': end_at,
        })
    return {
        "captions": captions,
        "audios": audios,
        "images": images,
        "videos": videos,
        "end_time": pre_time + segment_duration
    }

import re

_SENT_RE = re.compile(r'(?<=[。！？\n])')
_CLAUSE_RE = re.compile(r'(?<=[，,；;。！？!?、])')


def _split_content_list(items, count):
    if not isinstance(items, (list, tuple)):
        try:
            import json as _j
            items = _j.loads(str(items))
        except Exception:
            items = [str(items)] if items else []
    if not isinstance(items, list):
        items = list(items) if items else []
    count = max(int(count or 8), 1)
    if len(items) == count:
        return items
    full = ''.join(str(x) for x in items).strip()
    if not full:
        return items
    parts = [p.strip() for p in _SENT_RE.split(full) if p.strip()]
    if len(parts) < 3:
        parts = [p.strip() for p in _CLAUSE_RE.split(full) if p.strip()]
    if len(parts) <= 1:
        if count <= 1:
            return items
        full_text = str(full).strip()
        if not full_text:
            return items
        chunk_size = max(len(full_text) // count, 1)
        rough_segments = []
        start = 0
        for seg in range(count):
            end = len(full_text) if seg == count - 1 else min(len(full_text), start + chunk_size)
            piece = full_text[start:end].strip()
            if piece:
                rough_segments.append(piece)
            start = end
        return rough_segments if rough_segments else items
    target = min(count, len(parts))
    avg = len(parts) / target
    segments = []
    i = 0
    for seg in range(target):
        end_idx = len(parts) if seg == target - 1 else int((seg + 1) * avg)
        chunk = ''.join(parts[i:end_idx]).strip()
        if chunk:
            segments.append(chunk)
        i = end_idx
    return segments if segments else items


def _seconds_to_us(value, minimum=0):
    try:
        num = float(value or 0)
    except Exception:
        num = 0
    return max(int(num * 1000000), int(minimum or 0))


async def main(args: Args) -> Output:
    params = args.params

    intro_link = str(params.get('link') or '').strip()
    title_link = str(params.get('title_link') or '').strip()
    intro_us = _seconds_to_us(params.get('duration'), 1800000 if intro_link else 0)
    title_us = _seconds_to_us(params.get('title_duration'), 1200000 if title_link else 0)
    gap_after_intro = 0
    gap_after_title = 300000

    audios = []
    cursor = 0
    if intro_link and intro_us > 0:
        audios.append({
            'audio_url': intro_link,
            'duration': intro_us,
            'start': cursor,
            'end': cursor + intro_us,
        })
        cursor += intro_us + gap_after_intro

    if title_link and title_us > 0:
        audios.append({
            'audio_url': title_link,
            'duration': title_us,
            'start': cursor,
            'end': cursor + title_us,
        })
        cursor += title_us

    next_duration = cursor + gap_after_title
    # 正文起点不得早于神话草稿结构里 opening_window=4000000 的开场动画窗口
    if next_duration < 4000000:
        next_duration = 4000000

    images = []

    content_list = params.get('content_list') or []
    shuliang = params.get('shuliang') or 8
    content_items = _split_content_list(content_list, shuliang)
    content_items = [x for x in content_items if str(x or '').strip()]

    if content_items:
        content_items[0] = re.sub(r'^(今天(为大家|给大家|我们|咱们?)?(介绍|讲|说|认识)(的是)?[，,：: ]*)', '', str(content_items[0])).strip()
        if not content_items[0]:
            content_items = content_items[1:]

    def _strip_tail_punct(s):
        s = str(s or '').strip()
        if not s:
            return s
        return re.sub(r'[。！？!?]+\s*$', '', s).strip()

    content_items = [_strip_tail_punct(x) for x in content_items]
    content_items = [x for x in content_items if x]

    try:
        shuliang_int = max(int(shuliang or 8), 1)
    except Exception:
        shuliang_int = 8
    if len(content_items) > shuliang_int:
        content_items = content_items[:shuliang_int]

    return {
        'audios': audios,
        'images': images,
        'duration': intro_us,
        'nextDuration': next_duration,
        'content_items': content_items,
        'captions': [],
        'videos': [],
    }

