def add_scale_pop_keyframes(keyframes, segments):
    for seg in segments:
        if not isinstance(seg, dict):
            continue
        segment_id = str(seg.get('id') or '').strip()
        start = int(seg.get('start') or 0)
        end = int(seg.get('end') or start)
        if not segment_id or end <= start:
            continue
        keyframes.append({
            'offset': 0,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
            'value': 5.0,
        })
        keyframes.append({
            'offset': end - start,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
            'value': 1.0,
        })


def add_image_pan_keyframes(keyframes, segments):
    pan_cycle = [
        {'sx': -0.2, 'sy': -0.07, 'ex': 0, 'ey': 0, 'ss': 1.7, 'es': 1.2},
        {'sx': 0.22, 'sy': 0.05, 'ex': 0, 'ey': 0, 'ss': 1.75, 'es': 1.22},
        {'sx': -0.06, 'sy': 0.09, 'ex': 0, 'ey': 0, 'ss': 1.65, 'es': 1.18},
        {'sx': 0.18, 'sy': -0.07, 'ex': 0, 'ey': 0, 'ss': 1.7, 'es': 1.2},
        {'sx': -0.22, 'sy': 0.05, 'ex': 0, 'ey': 0, 'ss': 1.75, 'es': 1.22},
        {'sx': 0.05, 'sy': -0.09, 'ex': 0, 'ey': 0, 'ss': 1.68, 'es': 1.19},
    ]
    for idx, seg in enumerate(segments):
        if not isinstance(seg, dict):
            continue
        segment_id = str(seg.get('id') or '').strip()
        start = int(seg.get('start') or 0)
        end = int(seg.get('end') or start)
        if not segment_id or end <= start:
            continue
        motion = pan_cycle[idx % len(pan_cycle)]
        duration = end - start
        pan_dur = duration
        keyframes.append({
            'offset': 0,
            'property': 'KFTypePositionX',
            'segment_id': segment_id,
            'value': motion['sx'],
        })
        keyframes.append({
            'offset': pan_dur,
            'property': 'KFTypePositionX',
            'segment_id': segment_id,
            'value': motion['ex'],
        })
        keyframes.append({
            'offset': 0,
            'property': 'KFTypePositionY',
            'segment_id': segment_id,
            'value': motion['sy'],
        })
        keyframes.append({
            'offset': pan_dur,
            'property': 'KFTypePositionY',
            'segment_id': segment_id,
            'value': motion['ey'],
        })
        keyframes.append({
            'offset': 0,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
            'value': motion['ss'],
        })
        keyframes.append({
            'offset': pan_dur,
            'property': 'UNIFORM_SCALE',
            'segment_id': segment_id,
